sql:
SELECT AVG(incident_severity) AS average_severity
FROM incidents
WHERE state = 1 AND incident_date BETWEEN '2023-01-01' AND '2023-12-31';

external_knowledge:
- 'Notable incidents' refers to incidents with a severity greater than 1;
- 'Last year' specifically means the year 2022;
- 'Medium to high impact' corresponds to incident_severity > 1.

- "Troublesome storms" metaphorically refers to incidents with a severity greater than 3;
- "Unique storm identifiers" refers to incident IDs;
- "State they lashed" refers to the state where the incidents occurred;
- "Agencies that charted these tempests" refers to the agencies responsible for recording the incidents.

sql:
SELECT incident_id, incident_date 
FROM incidents 
ORDER BY incident_id;

SELECT AVG(incident_severity) AS average_severity
FROM incidents
WHERE incident_day = 1;

SELECT AVG(incident_severity) AS average_severity
FROM incidents
WHERE state = 1 AND incident_month = 6;

SELECT COUNT(*)
FROM incidents
WHERE state = 1 AND agency_id = 1;

SELECT COUNT(*) AS total_collisions
FROM incidents
WHERE incident_type = 1;

external_knowledge:
Incident severity greater than 2 indicates serious incidents; the higher the average number of occupants, the more populous the incidents are.;
"Kinds of incidents" refers to the different types of incidents, such as accidents or collisions.;
"Serious incidents" correspond to those with an incident severity above 2 in the database.;

sql:
SELECT COUNT(*) AS total_incidents
FROM incidents
WHERE state = 1;

SELECT MIN(incident_severity) AS most_severe_incident_severity
FROM incidents
WHERE state = 4 AND incident_date >= DATE('now', '-1 month');
